/* ============================================
   Enhanced Interactive Website Script
   ============================================ */

// ---- Particle Background ----
const ParticleSystem = {
  canvas: null,
  ctx: null,
  particles: [],
  mouse: { x: -1000, y: -1000 },
  count: 60,

  init() {
    this.canvas = document.getElementById('particles');
    if (!this.canvas) return;
    this.ctx = this.canvas.getContext('2d');
    this.resize();
    this.createParticles();
    this.animate();
    window.addEventListener('resize', () => this.resize());
    window.addEventListener('mousemove', (e) => {
      this.mouse.x = e.clientX;
      this.mouse.y = e.clientY;
    });
  },

  resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  },

  createParticles() {
    this.particles = [];
    const count = window.innerWidth < 768 ? 30 : this.count;
    for (let i = 0; i < count; i++) {
      this.particles.push({
        x: Math.random() * this.canvas.width,
        y: Math.random() * this.canvas.height,
        vx: (Math.random() - 0.5) * 0.4,
        vy: (Math.random() - 0.5) * 0.4,
        size: Math.random() * 2 + 0.5,
        opacity: Math.random() * 0.4 + 0.1
      });
    }
  },

  animate() {
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    this.particles.forEach((p, i) => {
      p.x += p.vx;
      p.y += p.vy;
      if (p.x < 0 || p.x > this.canvas.width) p.vx *= -1;
      if (p.y < 0 || p.y > this.canvas.height) p.vy *= -1;

      // Mouse interaction
      const dx = this.mouse.x - p.x;
      const dy = this.mouse.y - p.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 150) {
        p.x -= dx * 0.01;
        p.y -= dy * 0.01;
      }

      this.ctx.beginPath();
      this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      this.ctx.fillStyle = `rgba(127, 140, 255, ${p.opacity})`;
      this.ctx.fill();

      // Connect nearby particles
      for (let j = i + 1; j < this.particles.length; j++) {
        const p2 = this.particles[j];
        const d = Math.sqrt((p.x - p2.x) ** 2 + (p.y - p2.y) ** 2);
        if (d < 120) {
          this.ctx.beginPath();
          this.ctx.moveTo(p.x, p.y);
          this.ctx.lineTo(p2.x, p2.y);
          this.ctx.strokeStyle = `rgba(127, 140, 255, ${0.06 * (1 - d / 120)})`;
          this.ctx.stroke();
        }
      }
    });
    requestAnimationFrame(() => this.animate());
  }
};

// ---- Cursor Glow ----
const CursorGlow = {
  init() {
    const glow = document.querySelector('.cursor-glow');
    if (!glow || window.innerWidth < 768) return;
    window.addEventListener('mousemove', (e) => {
      glow.style.left = e.clientX + 'px';
      glow.style.top = e.clientY + 'px';
    });
  }
};

// ---- Scroll Progress Bar ----
const ScrollProgress = {
  init() {
    const bar = document.querySelector('.scroll-progress');
    if (!bar) return;
    window.addEventListener('scroll', () => {
      const scrollTop = window.scrollY;
      const docHeight = document.documentElement.scrollHeight - window.innerHeight;
      const progress = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;
      bar.style.width = progress + '%';
    }, { passive: true });
  }
};

// ---- Typing Effect ----
const TypingEffect = {
  phrases: [
    'Building Scalable Audit Systems',
    'Automating Risk Intelligence',
    'Designing Enforcement Pipelines',
    'Engineering Quality at Scale'
  ],
  el: null,
  phraseIndex: 0,
  charIndex: 0,
  isDeleting: false,
  delay: 80,

  init() {
    this.el = document.getElementById('typedText');
    if (!this.el) return;
    this.type();
  },

  type() {
    const current = this.phrases[this.phraseIndex];
    if (this.isDeleting) {
      this.el.textContent = current.substring(0, this.charIndex - 1);
      this.charIndex--;
      this.delay = 40;
    } else {
      this.el.textContent = current.substring(0, this.charIndex + 1);
      this.charIndex++;
      this.delay = 80;
    }

    if (!this.isDeleting && this.charIndex === current.length) {
      this.delay = 2000;
      this.isDeleting = true;
    } else if (this.isDeleting && this.charIndex === 0) {
      this.isDeleting = false;
      this.phraseIndex = (this.phraseIndex + 1) % this.phrases.length;
      this.delay = 400;
    }

    setTimeout(() => this.type(), this.delay);
  }
};

// ---- Navigation ----
const Navigation = {
  init() {
    this.setupHamburger();
    this.setupSmoothScroll();
    this.setupScrollSpy();
    this.setupNavShrink();
  },

  setupHamburger() {
    const hamburger = document.getElementById('hamburger');
    const navLinks = document.getElementById('navLinks');
    if (!hamburger || !navLinks) return;

    hamburger.addEventListener('click', () => {
      hamburger.classList.toggle('active');
      navLinks.classList.toggle('active');
      const expanded = hamburger.getAttribute('aria-expanded') === 'true';
      hamburger.setAttribute('aria-expanded', !expanded);
    });

    // Close on link click
    navLinks.querySelectorAll('.nav__link').forEach(link => {
      link.addEventListener('click', () => {
        hamburger.classList.remove('active');
        navLinks.classList.remove('active');
        hamburger.setAttribute('aria-expanded', 'false');
      });
    });
  },

  setupSmoothScroll() {
    document.querySelectorAll('a[href^="#"]').forEach(link => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        const target = document.getElementById(link.getAttribute('href').substring(1));
        if (target) {
          const offset = 70;
          const top = target.getBoundingClientRect().top + window.scrollY - offset;
          window.scrollTo({ top, behavior: 'smooth' });
        }
      });
    });
  },

  setupScrollSpy() {
    const sections = document.querySelectorAll('main section[id]');
    const navLinks = document.querySelectorAll('.nav__link');

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          navLinks.forEach(l => l.classList.remove('active'));
          const activeLink = document.querySelector(`.nav__link[href="#${entry.target.id}"]`);
          if (activeLink) activeLink.classList.add('active');
        }
      });
    }, { rootMargin: '-30% 0px -70% 0px' });

    sections.forEach(s => observer.observe(s));
  },

  setupNavShrink() {
    const nav = document.getElementById('navbar');
    if (!nav) return;
    window.addEventListener('scroll', () => {
      nav.classList.toggle('scrolled', window.scrollY > 50);
    }, { passive: true });
  }
};

// ---- Section Reveal ----
const SectionReveal = {
  init() {
    if (!('IntersectionObserver' in window)) {
      document.querySelectorAll('.section-reveal, .tilt-card').forEach(el => el.classList.add('visible'));
      return;
    }

    // Sections
    const sectionObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('visible');
          sectionObserver.unobserve(entry.target);
        }
      });
    }, { threshold: 0.1 });

    document.querySelectorAll('.section-reveal').forEach(el => sectionObserver.observe(el));

    // Staggered cards
    const cardObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const stagger = parseInt(entry.target.dataset.stagger || 0);
          setTimeout(() => {
            entry.target.classList.add('visible');
          }, stagger * 100);
          cardObserver.unobserve(entry.target);
        }
      });
    }, { threshold: 0.05 });

    document.querySelectorAll('.tilt-card').forEach(el => cardObserver.observe(el));
  }
};

// ---- Stat Counter Animation ----
const StatAnimations = {
  init() {
    const statValues = document.querySelectorAll('.stat-card__value[data-target]');
    if (statValues.length === 0) return;

    if (!('IntersectionObserver' in window)) {
      statValues.forEach(el => {
        const target = parseInt(el.dataset.target || '0', 10);
        const suffix = el.dataset.suffix || '';
        if (target > 0) el.textContent = target + suffix;
      });
      return;
    }

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (!entry.isIntersecting) return;
        const el = entry.target;
        if (el.dataset.animated === 'true') return;
        const target = parseInt(el.dataset.target || '0', 10);
        const suffix = el.dataset.suffix || '';
        if (target > 0) {
          this.animateValue(el, target, suffix, 1800);
          el.dataset.animated = 'true';
        }
        observer.unobserve(el);
      });
    }, { threshold: 0.3 });

    statValues.forEach(el => observer.observe(el));
  },

  animateValue(element, target, suffix, duration) {
    const startTime = performance.now();
    const tick = (currentTime) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3); // easeOutCubic
      const current = Math.round(target * eased);
      element.textContent = current + suffix;
      if (progress < 1) {
        requestAnimationFrame(tick);
      } else {
        element.textContent = target + suffix;
      }
    };
    requestAnimationFrame(tick);
  }
};

// ---- Card Tilt Effect ----
const TiltEffect = {
  init() {
    if (window.innerWidth < 768) return;
    document.querySelectorAll('.tilt-card').forEach(card => {
      card.addEventListener('mousemove', (e) => {
        const rect = card.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;
        const centerX = rect.width / 2;
        const centerY = rect.height / 2;
        const rotateX = ((y - centerY) / centerY) * -4;
        const rotateY = ((x - centerX) / centerX) * 4;
        card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) translateY(-4px)`;
      });

      card.addEventListener('mouseleave', () => {
        card.style.transform = '';
      });
    });
  }
};

// ---- Back to Top ----
const BackToTop = {
  init() {
    const btn = document.getElementById('backToTop');
    if (!btn) return;

    window.addEventListener('scroll', () => {
      btn.classList.toggle('visible', window.scrollY > 400);
    }, { passive: true });

    btn.addEventListener('click', () => {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
  }
};

// ---- Magnetic Buttons ----
const MagneticButtons = {
  init() {
    if (window.innerWidth < 768) return;
    document.querySelectorAll('.magnetic-btn').forEach(btn => {
      btn.addEventListener('mousemove', (e) => {
        const rect = btn.getBoundingClientRect();
        const x = e.clientX - rect.left - rect.width / 2;
        const y = e.clientY - rect.top - rect.height / 2;
        btn.style.transform = `translate(${x * 0.15}px, ${y * 0.15}px)`;
      });

      btn.addEventListener('mouseleave', () => {
        btn.style.transform = '';
      });
    });
  }
};

// ---- Initialize Everything ----
document.addEventListener('DOMContentLoaded', () => {
  ParticleSystem.init();
  CursorGlow.init();
  ScrollProgress.init();
  TypingEffect.init();
  Navigation.init();
  SectionReveal.init();
  StatAnimations.init();
  TiltEffect.init();
  BackToTop.init();
  MagneticButtons.init();
});
